package com.careeros.provider.infrastructure.generic;

import com.careeros.company.domain.Company;import com.careeros.job.application.JobPostingCommand;import com.careeros.job.infrastructure.ingestion.support.*;import com.careeros.provider.application.JobProvider;import com.careeros.provider.domain.ProviderType;import com.fasterxml.jackson.databind.*;import org.springframework.stereotype.Component;import org.springframework.web.client.RestClient;import java.time.LocalDate;import java.util.*;
@Component public class GenericJsonProvider implements JobProvider{private final RestClient client;private final ObjectMapper mapper;public GenericJsonProvider(RestClient.Builder b,ObjectMapper m){client=b.build();mapper=m;}public ProviderType providerType(){return ProviderType.GENERIC_JSON;}public List<JobPostingCommand>fetchJobs(Company c){var cfg=new ProviderConfiguration(mapper,c.getProviderConfiguration());String body=GenericProviderSupport.retry(3,()->client.get().uri(cfg.required("endpoint")).retrieve().body(String.class));try{JsonNode root=mapper.readTree(body),items=at(root,Optional.ofNullable(cfg.text("itemsField")).orElse(""));if(!items.isArray())throw new IllegalArgumentException("Configured jobs node is not an array");List<JobPostingCommand>out=new ArrayList<>();for(JsonNode n:items){String title=value(n,cfg.required("titleField")),apply=value(n,cfg.required("urlField"));if(title==null||apply==null)continue;String loc=value(n,cfg.text("locationField")),desc=value(n,cfg.text("descriptionField")),id=value(n,cfg.text("idField"));out.add(new JobPostingCommand(id==null?Integer.toHexString(apply.hashCode()):id,c.getId(),title,loc,EmploymentTypeParser.fromKeyword(title),RemoteHeuristic.looksRemote(title,loc),null,null,null,desc,LocalDate.now(),apply));}return out;}catch(Exception e){throw new IllegalArgumentException("Unable to map JSON job feed",e);}}private JsonNode at(JsonNode n,String path){if(path==null||path.isBlank())return n;for(String p:path.split("\\.")){n=n.path(p);}return n;}private String value(JsonNode n,String path){if(path==null||path.isBlank())return null;JsonNode v=at(n,path);return v.isMissingNode()||v.isNull()?null:v.asText();}}
